    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Kids Fitness Fun - 2w 3x/wk',
    'kids_youth',
    3,
    60,
    ARRAY['Build functional strength', 'Improve body control']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Kids Fitness Fun'
ON CONFLICT DO NOTHING;

